module checksum_calculator (
    input [7:0] data_in,
    output reg [7:0] checksum_out
);
    integer i;
    reg [7:0] checksum_sum;

    always @(*) begin
        checksum_sum = 8'b0;
        for (i = 0; i < 8; i = i + 1) begin
            checksum_sum = checksum_sum + data_in[i];
        end
        checksum_out = checksum_sum % 256;
    end
endmodule
